UPDATE resource_emotion_arc
SET generate_status = #{generateStatus},
    error_message   = #{errorMessage}
WHERE resource_id = #{resourceId}
  AND deleted = 0

UPDATE resource_emotion_arc
SET deleted = 1
WHERE resource_id = #{resourceId}

UPDATE resource_emotion_arc
SET deleted = 1
WHERE arc_id = #{arcId}

mapper.select:
SELECT COUNT(*) FROM resource_emotion_arc rea LEFT JOIN resource r ON rea.resource_id = r.resource_id WHERE rea.deleted = 0
AND rea.resource_id = #{resourceId}
AND rea.generate_status = #{generateStatus}
AND r.title LIKE CONCAT('%', #{keyword}, '%')

SELECT rea.*
FROM resource_emotion_arc rea
LEFT JOIN resource r ON rea.resource_id = r.resource_id
WHERE rea.deleted = 0

    AND rea.resource_id = #{resourceId}


    AND rea.generate_status = #{generateStatus}


    AND r.title LIKE CONCAT('%', #{keyword}, '%')

ORDER BY rea.ctime DESC

    LIMIT #{offset}, #{limit}
